// Summary: Tests Footer rendering of div wrapper, child passthrough, and className merging behavior.

import '@testing-library/jest-dom';
import * as React from 'react';
import { render, screen } from '@testing-library/react';
import { Footer } from './Footer';

describe('Footer', () => {
  it('renders a div and exposes children', () => {
    render(
      <Footer data-testid="footer">
        <span>Child</span>
      </Footer>
    );

    const element = screen.getByTestId('footer');

    expect({
      tag: element.tagName,
      text: element.textContent?.trim()
    }).toEqual({ tag: 'DIV', text: 'Child' });
  });

  it('merges custom className with base token', () => {
    render(
      <Footer data-testid="footer" className="custom-footer">
        Content
      </Footer>
    );

    const className = screen.getByTestId('footer').className;

    expect({
      hasBase: className.includes('background-footer'),
      hasCustom: className.includes('custom-footer')
    }).toEqual({ hasBase: true, hasCustom: true });
  });
});
